    output.ketqua = `time_ranges=[{"since":"${input.time_ranges_since}","until":"${input.time_ranges_until}"}]`;
} else if (input.date_preset && (!input.time_ranges_since || !input.time_ranges_until)) {
    output.ketqua = `date_preset=${input.date_preset}`;
} else {
    output.ketqua = "Không có điều kiện hợp lệ.";
}

// Trả kết quả
return [{ json: output }];

